// Payload esperado del Terminal Institucional:
// {
//   estrategia : string   (nombre de la estrategia)
//   tipo_senal : string   ('compra' | 'venta')
//   telefono   : string   (número WhatsApp destino, ej. '5493515280277' o '+549...' o '...@s.whatsapp.net')
//   simbolo    : string   (ej. 'BTCUSDT')
//   precio     : number   (precio al momento de la señal)
//   timestamp  : number   (Unix ms)
// }

const body = $input.first().json.body;

// Normalizar número: quitar @s.whatsapp.net y espacios/guiones/+ si los hubiera
const telefonoRaw = (body.telefono || '').replace('@s.whatsapp.net', '').replace(/[\s\-\+]/g, '');

const senal = (body.tipo_senal || 'compra').toLowerCase();
const emoji = senal === 'venta' ? '🔴' : '🟢';
const tipo  = senal === 'venta' ? 'VENTA' : 'COMPRA';

const fecha = new Date(body.timestamp || Date.now());
const opciones = { timeZone: 'America/Argentina/Buenos_Aires' };
const hora = fecha.toLocaleTimeString('es-AR', { ...opciones, hour: '2-digit', minute: '2-digit' });
const fechaStr = fecha.toLocaleDateString('es-AR', { ...opciones, day: '2-digit', month: '2-digit', year: '2-digit' });

const precio = Number(body.precio || 0)
  .toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

const texto =
  `${emoji} *SEÑAL DE ${tipo}*\n` +
  `━━━━━━━━━━━━━━\n` +
  `📌 *Estrategia:* ${body.estrategia || '—'}\n` +
  `📊 *Símbolo:* ${body.simbolo || 'BTCUSDT'}\n` +
  `💵 *Precio:* $${precio}\n` +
  `🕐 *${fechaStr} ${hora} (ARG)*\n\n` +
  `_Terminal Institucional_`;

return [{ json: { telefono: telefonoRaw, texto } }];
